def test_consolidate_initializes_missing_user_history_with_canonical_ledger(
    tmp_path, monkeypatch
):
    project_root = _write_user_project(tmp_path, create_history=False)
    source = _write_log(project_root, 1, goal="Initialize missing history")
    monkeypatch.chdir(project_root)

    exit_code, message = consolidate_module._run_consolidate_command(
        consolidate_module.ConsolidateOptions(
            by_age=True,
            days=0,
            all=True,
            quiet=True,
        )
    )

    history_path = project_root / "docs" / "strategy" / "decision_history.md"
    archived_path = project_root / "docs" / "archive" / "logs" / source.name
    history = history_path.read_text(encoding="utf-8")
    assert exit_code == 0
    assert message == "Consolidated 1 logs"
    assert not source.exists()
    assert archived_path.exists()
    assert history.startswith("---\nid: decision_history\n")
    assert history.count(CANONICAL_LEDGER_SECTION) == 1
    assert f"`docs/archive/logs/{source.name}`" in history


def test_consolidate_self_heals_generated_narrative_preserving_prefix(
    tmp_path, monkeypatch
):
    project_root = _write_user_project(
        tmp_path,
        history_content=GENERATED_NARRATIVE_HISTORY,
    )
    source = _write_log(project_root, 1, goal="Preserve narrative")
    history_path = project_root / "docs" / "strategy" / "decision_history.md"
    original = history_path.read_bytes()
    monkeypatch.chdir(project_root)

    exit_code, _ = consolidate_module._run_consolidate_command(
        consolidate_module.ConsolidateOptions(
            by_age=True,
            days=0,
            all=True,
            quiet=True,
        )
    )

    updated = history_path.read_bytes()
    assert exit_code == 0
    assert updated[: len(original)] == original
    assert updated.decode("utf-8").count(CANONICAL_LEDGER_SECTION) == 1
    assert f"`docs/archive/logs/{source.name}`" in updated.decode("utf-8")


def test_consolidate_self_heal_preserves_crlf_narrative_bytes(
    tmp_path, monkeypatch
):
    crlf_history = GENERATED_NARRATIVE_HISTORY.replace("\n", "\r\n")
    project_root = _write_user_project(
        tmp_path,
        history_content="",
    )
    source = _write_log(project_root, 1, goal="Preserve CRLF narrative")
    history_path = project_root / "docs" / "strategy" / "decision_history.md"
    original = crlf_history.encode("utf-8")
    history_path.write_bytes(original)
    monkeypatch.chdir(project_root)

    exit_code, _ = consolidate_module._run_consolidate_command(
        consolidate_module.ConsolidateOptions(
            by_age=True,
            days=0,
            all=True,
            quiet=True,
        )
    )

    updated = history_path.read_bytes()
    assert exit_code == 0
    assert updated.startswith(original)
    assert updated[: len(original)].count(b"\r\n") == original.count(b"\r\n")
    assert f"`docs/archive/logs/{source.name}`".encode() in updated


