def test_append_to_decision_history_is_idempotent_for_archive_path(tmp_path):
    project_root = _write_user_project(tmp_path)
    history_path = project_root / "docs" / "strategy" / "decision_history.md"
    archive_path = "docs/archive/logs/2020-01-01-repeat.md"

    first_context = consolidate_module.SessionContext.from_repo(project_root)
    assert consolidate_module.append_to_decision_history(
        "2020-01-01",
        "repeat",
        "chore",
        "First summary",
        [],
        archive_path,
        history_path,
        first_context,
        consolidate_module.OutputHandler(quiet=True),
    )
    first_context.commit()
    first_content = history_path.read_text(encoding="utf-8")

    second_context = consolidate_module.SessionContext.from_repo(project_root)
    assert consolidate_module.append_to_decision_history(
        "2020-01-01",
        "repeat",
        "chore",
        "Replacement summary",
        [],
        archive_path,
        history_path,
        second_context,
        consolidate_module.OutputHandler(quiet=True),
    )
    assert second_context.commit() == []

    assert history_path.read_text(encoding="utf-8") == first_content
    assert first_content.count(f"`{archive_path}`") == 1
    assert "First summary" in first_content
    assert "Replacement summary" not in first_content


def test_tracked_decision_history_template_uses_exact_canonical_ledger():
    repository_root = Path(__file__).resolve().parents[2]
    template = (
        repository_root / ".ontos" / "templates" / "decision_history_template.md"
    ).read_text(encoding="utf-8")

    assert template.count(CANONICAL_LEDGER_SECTION) == 1
